cards.content:
{% set raw = states('sensor.gwmbrasil_lgwffua59sh903754_status_message') %}          {% if raw in ['unknown','unavailable','', None] %}
  {% set mensagens = [] %}
{% else %}
  {% set mensagens = raw.split('|') %}
{% endif %}
{% set textos = {
  "NO_ALERTS": "Não há alertas neste momento.",
  "ERR_FORMATTING_ADDRESS": "Erro ao formatar endereço.",
  "ERR_GENERATE_RESPONSE": "Desculpe, houve um erro ao gerar a resposta.",
  "ALERT_HIGH_VOLTAGE_DISCONNECT": "A bateria de alta tensão já está totalmente carregada. O carregador deve ser desconectado.",
  "SUNROOF_OPEN": "O teto solar está aberto.",
  "UNLOCKED": "A trava das portas não está acionada e o veículo pode ser aberto.",
  "ENGINE_ON_AND_UNLOCKED": "O motor está ligado e o veículo está destravado. Verifique se não foi esquecido ligado.",
  "FUEL_LOW": "Nível de combustível abaixo de 15 litros. Recomenda-se abastecer.",
  "AC_ON_WITH_ENGINE_OFF": "O ar-condicionado está ligado com o veículo desligado. Isso pode drenar a bateria de 12V.",
  "REVIEW_PREFIX": "Seu veículo está dentro do limite padrão de quilometragem para agendar a revisão."
} %}
{% for item in mensagens %}
  {% set partes = item.split('@') %}
  {% set codigo = partes[0] | trim %}
  {% if codigo in textos %}
  • {{ textos.get(codigo) }}
  {% elif codigo == 'VEHICLE_CHARGING_TIME' and partes|length >= 2 %}
  • O veículo está carregando. Tempo aproximado para carga total: {{ partes[1] }}.
  {% elif codigo == 'WINDOW_OPEN' and partes|length >= 2 %}
  • O {{ partes[1] }} está aberto.
  {% elif codigo == 'DOOR_OPEN' and partes|length >= 2 %}
  • A {{ partes[1] }} está aberta.
  {% elif codigo == 'TRUNK_OPEN' and partes|length >= 2 %}
  • O {{ partes[1] }} está aberto.
  {% elif codigo == 'BATTERY_12V_CRITICAL' and partes|length >= 2 %}
  • 🔴 Alerta crítico: bateria 12V em {{ partes[1] }}%. Ligue o motor o quanto antes.
  {% elif codigo == 'BATTERY_12V_ALERT' and partes|length >= 2 %}
  • 🟠 Atenção: bateria 12V em {{ partes[1] }}%.
  {% elif codigo == 'TIRE_PRESSURE' and partes|length >= 4 %}
  • A {{ partes[1] }} está em {{ partes[2] }} psi com temperatura de {{ partes[3] }}.
  {% elif codigo == 'TIRE_PRESSURE_DEFAULTS' and partes|length >= 3 %}
  • A pressão recomendada pela montadora é entre {{ partes[1] }} e {{ partes[2] }} psi.
  {% elif codigo == 'SERVICE_WITH_TOLERANCE' and partes|length >= 2 %}
  • Veículo no limite para revisão. Restam {{ partes[1] }} km antes da perda da garantia.
  {% else %}
  • {{ item }}
  {% endif %}

{% endfor %}

