custom_fields.status:
[[[
  const sensors = [
    `sensor.gwmbrasil_lgwffua59sh903754_vidro_dianteiro_esquerdo`,
    `sensor.gwmbrasil_lgwffua59sh903754_vidro_dianteiro_direito`,
    `sensor.gwmbrasil_lgwffua59sh903754_vidro_traseiro_esquerdo`,
    `sensor.gwmbrasil_lgwffua59sh903754_vidro_traseiro_direito`
  ];

  const values = sensors
    .map(e => states[e]?.state)
    .filter(v => v !== undefined && v !== 'none');

  if (values.length === 0) return '';

  const anyOpen = values.some(v => v !== '1');

  const color = anyOpen ? '#f87171' : '#4ade80';
  const text  = anyOpen ? 'Abertos' : 'Fechados';

  return `
    <span style="display:flex;align-items:center;gap:6px;">
      <span style="
        width:6px;
        height:6px;
        border-radius:50%;
        background:` + color + `;
        animation:pulse 2s infinite;
      "></span>
      <span style="font-size:11px;color:` + color + `;">
        ` + text + `
      </span>
    </span>
  `;
]]]

